def range_summary(nums):
    if not nums:  # empty list returns ''
        return ''

    sorted_nums = sorted(set(nums))  # remove duplicates, sort
    result = []
    start = None

    for num in sorted_nums:
        if start is None or num == start + 1:
            if start is not None:
                result.append(f'{start}-{num}')
            else:
                result.append(str(num))
            start = num
        else:
            result.append(str(num))

    return ','.join(result)
